# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from sklearn.model_selection import train_test_split
from sklearn.ensemble import RandomForestClassifier
import numpy as np
import pickle

app = Flask(__name__)

# In-memory storage for images and labels
image_labels = defaultdict(list)

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    image_labels[image_id].append(label)
    return jsonify({"message": "Label submitted successfully"}), 200

def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        most_common_label = Counter(labels).most_common(1)[0][0]
        aggregated_labels[image_id] = most_common_label
    return aggregated_labels

def train_model(aggregated_labels):
    # Dummy feature extraction: using image_id as feature
    X = np.array([[int(image_id)] for image_id in aggregated_labels.keys()])
    y = np.array(list(aggregated_labels.values()))
    
    # Train-test split (no validation as per requirement)
    X_train, _, y_train, _ = train_test_split(X, y, test_size=0.0, random_state=42)
    
    # Train a simple model
    model = RandomForestClassifier()
    model.fit(X_train, y_train)
    
    # Save the model
    with open('model.pkl', 'wb') as f:
        pickle.dump(model, f)

@app.route('/train', methods=['POST'])
def train():
    aggregated_labels = aggregate_labels()
    train_model(aggregated_labels)
    return jsonify({"message": "Model trained successfully"}), 200

if __name__ == '__main__':
    app.run(debug=True)